% This function predicts R and K times given the TEG model parameters
function [R, K] = TEG_RK_Prediction(timespan, simTEG, Kd1, Kp1)
% Inputs: timespan is a vector for the simulated TEG profile
%         simTEG is the simulated TEG profile generated by model parameters

arguments
    timespan (:,1) double
    simTEG (:,1) double
    Kd1 double = -1
    Kp1 double = -1
end


% R_amp_threshold = 2.9372;
% K_amp_threshold = 39.097;
R_amp_threshold = 4;
K_amp_threshold = 40;

for i = 1:length(timespan)
    if simTEG(i) >= R_amp_threshold
        R_idx_after = i;
        R_idx_prev = i - 1;
        break;
    end
end
for i = 1:length(timespan)
    if simTEG(i) >= K_amp_threshold
        K_idx_after = i;
        K_idx_prev = i - 1;
        break;
    end
end

if all(simTEG < K_amp_threshold)
    [~, K_idx_after] = max(simTEG);
    K_idx_prev = K_idx_after - 1;
end

if exist('R_idx_prev', 'var')
    R_est_from_curve = 0.5*(timespan(R_idx_prev) + timespan(R_idx_after));
    if Kd1 < 0 || Kp1 < 0
        R = R_est_from_curve;
    else
        predicted_R_prediction_error = -0.5112*Kd1 - 6.7719*1/Kp1 + 10.043;       % Trend line equation from dataset S1C S2C S3C and 112524
        % R_corrected = predicted_R_prediction_error*R_est_from_curve/100 + R_est_from_curve;
        R_corrected = R_est_from_curve/(predicted_R_prediction_error/100 + 1);
        R = 0.5*(R_est_from_curve + R_corrected);
    end
    K = 0.5*(timespan(K_idx_prev) + timespan(K_idx_after)) - R;
else
    R = -1;
    K = -1;
end